import React, { useEffect, useMemo, useState } from 'react';
import PropTypes from 'prop-types';
import styled from 'styled-components';
import { Layout, About, Jobs, Featured, HomeBlogPreview, Contact } from '@components';
import { navLinks, socialMedia, email } from '@config';
import { Icon } from '@components/icons';

const StyledHomePage = styled.main`
  position: relative;
  isolation: isolate;
  width: 100%;
  margin: 0 auto;
  padding: 64px 90px 72px;
  max-width: none;
  min-height: 100vh;
  color: var(--slate);
  --navy: #0b1220;
  --dark-navy: #0f172a;
  --light-navy: #111b2e;
  --surface-secondary: rgba(15, 23, 42, 0.72);
  --lightest-navy: rgba(148, 163, 184, 0.18);
  --navy-shadow: rgba(2, 6, 23, 0.55);
  --dark-slate: #cbd5e1;
  --slate: #8fa1ba;
  --light-slate: #64748b;
  --lightest-slate: #e5edf7;
  --white: #f8fafc;
  --green: #5eead4;
  --green-tint: rgba(94, 234, 212, 0.12);
  background: transparent;

  @media (max-width: 1080px) {
    padding: 52px 70px 60px;
  }

  @media (max-width: 900px) {
    padding: 38px 42px 48px;
  }

  @media (max-width: 480px) {
    padding: 28px 24px 36px;
  }

  .numbered-heading {
    color: var(--lightest-slate);
  }
`;

const StyledHomeGrid = styled.div`
  position: relative;
  z-index: 1;
  display: grid;
  width: 100%;
  max-width: 1180px;
  margin: 0 auto;
  grid-template-columns: minmax(260px, 340px) minmax(0, 1fr);
  gap: 72px;
  align-items: start;

  @media (max-width: 1080px) {
    gap: 56px;
    grid-template-columns: minmax(240px, 300px) minmax(0, 1fr);
  }

  @media (max-width: 900px) {
    grid-template-columns: 1fr;
    gap: 38px;
  }
`;

const StyledSidebar = styled.aside`
  position: sticky;
  top: 64px;
  align-self: start;
  padding: 10px 0 40px;

  @media (max-width: 1080px) {
    top: 52px;
  }

  @media (max-width: 900px) {
    position: static;
    padding-bottom: 0;
  }
`;

const StyledIntro = styled.div`
  .eyebrow {
    color: var(--green);
    font-family: var(--font-ui);
    font-size: var(--fz-sm);
    font-weight: 600;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    margin-bottom: 16px;
  }

  h1 {
    margin: 0;
    font-size: clamp(48px, 5vw, 72px);
    line-height: 0.94;
    letter-spacing: -0.05em;
  }

  .role {
    margin-top: 12px;
    color: var(--dark-slate);
    font-size: clamp(18px, 2.1vw, 23px);
    font-weight: 500;
  }

  .summary {
    margin-top: 18px;
    max-width: 32ch;
    color: var(--light-slate);
    font-size: var(--fz-md);
    line-height: 1.8;
  }
`;

const StyledSectionNav = styled.nav`
  margin: 42px 0 38px;

  @media (max-width: 900px) {
    margin: 28px 0 28px;
  }

  ol {
    list-style: none;
    padding: 0;
    margin: 0;
  }

  li + li {
    margin-top: 14px;
  }

  a {
    display: inline-flex;
    align-items: center;
    gap: 16px;
    color: var(--light-slate);
    font-family: var(--font-ui);
    font-weight: 600;
    text-transform: uppercase;
    font-size: var(--fz-xs);
    transition: var(--transition);
    letter-spacing: 0.1em;
  }

  a:before {
    content: '';
    display: block;
    width: 48px;
    height: 1px;
    background-color: var(--lightest-navy);
    transition: var(--transition);
  }

  a:hover,
  a:focus {
    color: var(--dark-slate);
  }

  a.active {
    color: var(--lightest-slate);
  }

  a.active:before {
    width: 72px;
    background-color: var(--green);
  }
`;

const StyledSidebarActions = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin: 30px 0 32px;

  a {
    ${({ theme }) => theme.mixins.smallButton};
    font-size: var(--fz-xs);
  }
`;

const StyledSocialRow = styled.ul`
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 0;
  margin: 0;
  list-style: none;

  a {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 40px;
    height: 40px;
    border-radius: 999px;
    color: var(--light-slate);
    background-color: rgba(15, 23, 42, 0.55);
    border: 1px solid rgba(148, 163, 184, 0.16);
    box-shadow: 0 10px 24px -18px var(--navy-shadow);
    transition: var(--transition);
  }

  a:hover,
  a:focus {
    color: var(--green);
    background-color: var(--green-tint);
    transform: translateY(-2px);
  }

  svg {
    width: 18px;
    height: 18px;
  }
`;

const StyledContent = styled.div`
  min-width: 0;

  section {
    margin: 0;
    max-width: 100%;
    scroll-margin-top: 90px;
  }

  section + section {
    margin-top: 80px;
  }

  section:not(:first-of-type) {
    padding-top: 28px;
    border-top: 1px solid rgba(148, 163, 184, 0.14);
  }

  @media (max-width: 900px) {
    section + section {
      margin-top: 60px;
    }
  }
`;

const IndexPage = ({ location }) => {
  const sectionLinks = useMemo(() => navLinks.filter(({ url }) => url.startsWith('/#')), []);
  const [activeNavLink, setActiveNavLink] = useState('/#about');

  useEffect(() => {
    if (location.hash) {
      setActiveNavLink(`/${location.hash}`);
    }
  }, [location.hash]);

  useEffect(() => {
    if (typeof window === 'undefined') {
      return undefined;
    }

    const sections = sectionLinks
      .map(({ url }) => ({
        url,
        el: document.getElementById(url.replace('/#', '')),
      }))
      .filter(item => item.el);

    if (sections.length === 0) {
      return undefined;
    }

    const observer = new IntersectionObserver(
      entries => {
        const visible = entries
          .filter(entry => entry.isIntersecting)
          .sort((a, b) => b.intersectionRatio - a.intersectionRatio);

        if (visible.length > 0) {
          const activeSection = sections.find(item => item.el === visible[0].target);
          if (activeSection) {
            setActiveNavLink(activeSection.url);
          }
        }
      },
      {
        rootMargin: '-28% 0px -56% 0px',
        threshold: [0.1, 0.25, 0.4, 0.6],
      },
    );

    sections.forEach(section => observer.observe(section.el));

    return () => {
      sections.forEach(section => observer.unobserve(section.el));
      observer.disconnect();
    };
  }, [sectionLinks]);

  return (
    <Layout location={location}>
      <StyledHomePage>
        <StyledHomeGrid>
          <StyledSidebar>
            <StyledIntro>
              <h1>Thomas Doan.</h1>
              <div className="role">Frontend Engineer</div>
              <p className="summary">
                I build accessible, pixel-perfect experiences for the web.
              </p>
            </StyledIntro>

            <StyledSectionNav aria-label="Section navigation">
              <ol>
                <li>
                  <a
                    href="/#about"
                    className={activeNavLink === '/#about' ? 'active' : ''}
                    aria-current={activeNavLink === '/#about' ? 'page' : undefined}>
                    About
                  </a>
                </li>
                <li>
                  <a
                    href="/#jobs"
                    className={activeNavLink === '/#jobs' ? 'active' : ''}
                    aria-current={activeNavLink === '/#jobs' ? 'page' : undefined}>
                    Experience
                  </a>
                </li>
                <li>
                  <a
                    href="/#projects"
                    className={activeNavLink === '/#projects' ? 'active' : ''}
                    aria-current={activeNavLink === '/#projects' ? 'page' : undefined}>
                    Projects
                  </a>
                </li>
                <li>
                  <a
                    href="/#contact"
                    className={activeNavLink === '/#contact' ? 'active' : ''}
                    aria-current={activeNavLink === '/#contact' ? 'page' : undefined}>
                    Contact
                  </a>
                </li>
              </ol>
            </StyledSectionNav>

            <StyledSidebarActions>
              <a href="/resume.pdf" target="_blank" rel="noopener noreferrer">
                Resume
              </a>
              <a href={`mailto:${email}`}>Email</a>
            </StyledSidebarActions>

            <StyledSocialRow aria-label="Social links">
              {socialMedia.map(({ url, name }) => (
                <li key={name}>
                  <a href={url} aria-label={name} target="_blank" rel="noopener noreferrer">
                    <Icon name={name} />
                  </a>
                </li>
              ))}
            </StyledSocialRow>
          </StyledSidebar>

          <StyledContent>
            <About />
            <Jobs />
            <Featured />
            <HomeBlogPreview />
            <Contact />
          </StyledContent>
        </StyledHomeGrid>
      </StyledHomePage>
    </Layout>
  );
};

IndexPage.propTypes = {
  location: PropTypes.object.isRequired,
};

export default IndexPage;
